        public static void SaveEntity2DataTable(DataTable table, BvConversationMessagesEntity entity)
        {
            var rowData = new object[]
                {
                    entity.Id,
                    entity.ConversationId,
                    entity.Date,
                    entity.Body,
                    entity.SenderType,
                    entity.SenderId,
                    entity.SenderFullName
                };

            table.Rows.Add(rowData);
        }
    }
}
